     1→import { NestFactory } from '@nestjs/core';
     2→import { AppModule } from './app.module';
     3→import { ValidationPipe } from '@nestjs/common';
     4→import { appConfig } from '@configs/app.config';
     5→import { DocumentBuilder, SwaggerModule } from '@nestjs/swagger';
     6→
     7→async function bootstrap() {
     8→  const app = await NestFactory.create(AppModule);
     9→  app.useGlobalPipes(new ValidationPipe());
    10→
    11→  const appConf = appConfig();
    12→
    13→  if (appConf.swagger.enabled) {
    14→    const config = new DocumentBuilder()
    15→      .setTitle('Cryptonly API')
    16→      .setDescription('API for the Cryptonly product')
    17→      .setVersion('1.0')
    18→      .build();
    19→    const document = SwaggerModule.createDocument(app, config);
    20→    document.components.securitySchemes = {
    21→      JWT: {
    22→        type: 'http',
    23→        scheme: 'bearer',
    24→      },
    25→      TENANT_API_KEY: {
    26→        type: 'apiKey',
    27→        in: 'header',
    28→        name: 'x-tenant-api-key',
    29→      },
    30→    };
    31→    SwaggerModule.setup(appConf.swagger.uiUri, app, document);
    32→  }
    33→
    34→  await app.listen(appConf.port);
    35→}
    36→bootstrap();
    37→

