     1→import {
     2→  CanActivate,
     3→  ExecutionContext,
     4→  HttpException,
     5→  HttpStatus,
     6→  Injectable,
     7→  UnauthorizedException,
     8→} from '@nestjs/common';
     9→import { DATABASE_CONNECTION_TOKEN } from '@shared/database/constant';
    10→import { Db } from '@shared/database/types';
    11→import { Inject } from '@nestjs/common';
    12→import { DEFAULT_REDIS_TOKEN } from '@configs/index';
    13→import { IRedisClient } from '@podkopaev-tech/nest-infra-modules';
    14→import { RateLimiterRedis } from 'rate-limiter-flexible';
    15→
    16→@Injectable()
    17→export class RateLimitGuard implements CanActivate {
    18→  constructor(
    19→    @Inject(DATABASE_CONNECTION_TOKEN) private readonly db: Db,
    20→    @Inject(DEFAULT_REDIS_TOKEN) private readonly redis: IRedisClient,
    21→  ) {
    22→    this.rateLimiter = new RateLimiterRedis({
    23→      points: 1000,
    24→      duration: 60,
    25→      storeClient: this.redis,
    26→    });
    27→  }
    28→  private readonly rateLimiter: RateLimiterRedis;
    29→
    30→  async canActivate(context: ExecutionContext): Promise<boolean> {
    31→    const request = context.switchToHttp().getRequest();
    32→    const apiKey = request.headers['x-tenant-account-api-key'];
    33→    if (!apiKey) {
    34→      throw new UnauthorizedException('API key is required');
    35→    }
    36→
    37→    const rateLimiter = await this.rateLimiter.consume(apiKey);
    38→    if (!rateLimiter.consumedPoints) {
    39→      throw new HttpException(
    40→        `Rate limit exceeded. Try again in ${Math.round(rateLimiter.msBeforeNext / 1000)} seconds.`,
    41→        HttpStatus.TOO_MANY_REQUESTS,
    42→      );
    43→    }
    44→    return true;
    45→  }
    46→}
    47→

