     1→import { Injectable, UnauthorizedException } from '@nestjs/common';
     2→import { PassportStrategy } from '@nestjs/passport';
     3→import { ExtractJwt, Strategy } from 'passport-jwt';
     4→import { ConfigType } from '@nestjs/config';
     5→import { jwtConfig } from '@configs/jwt.config';
     6→import { Db } from '@shared/database/types';
     7→import { DATABASE_CONNECTION_TOKEN } from '@shared/database/constant';
     8→import { Inject } from '@nestjs/common';
     9→import { UUID } from 'crypto';
    10→
    11→export interface JwtPayload {
    12→  sub: string; // user id
    13→  email: string;
    14→  tenantId: number;
    15→}
    16→
    17→@Injectable()
    18→export class JwtStrategy extends PassportStrategy(Strategy) {
    19→  constructor(
    20→    @Inject(jwtConfig.KEY)
    21→    private readonly config: ConfigType<typeof jwtConfig>,
    22→    @Inject(DATABASE_CONNECTION_TOKEN)
    23→    private readonly db: Db,
    24→  ) {
    25→    super({
    26→      jwtFromRequest: ExtractJwt.fromAuthHeaderAsBearerToken(),
    27→      ignoreExpiration: false,
    28→      secretOrKey: config.secret,
    29→    });
    30→  }
    31→
    32→  async validate(payload: JwtPayload) {
    33→    console.log(payload);
    34→    const user = await this.db
    35→      .selectFrom('user')
    36→      .selectAll()
    37→      .where('id', '=', payload.sub as UUID)
    38→      .where('isActive', '=', true)
    39→      .executeTakeFirst();
    40→
    41→    if (!user) {
    42→      throw new UnauthorizedException('User not found or inactive');
    43→    }
    44→
    45→    return {
    46→      id: user.id,
    47→      email: user.email,
    48→      tenantId: user.tenantId,
    49→      role: user.role,
    50→    };
    51→  }
    52→}
    53→

