    10→export class TenantApiKeyAuthGuard implements CanActivate {
    11→  constructor(private readonly apiKeyService: ApiKeyService) {}
    12→
    13→  async canActivate(context: ExecutionContext): Promise<boolean> {
    14→    const request = context.switchToHttp().getRequest();
