     1→import { Injectable, UnauthorizedException, Inject } from '@nestjs/common';
     2→import { JwtService, JwtSignOptions } from '@nestjs/jwt';
     3→import { ConfigType } from '@nestjs/config';
     4→import { jwtConfig } from '@configs/jwt.config';
     5→import { Db } from '@shared/database/types';
     6→import { DATABASE_CONNECTION_TOKEN } from '@shared/database/constant';
     7→import { randomBytes, UUID } from 'crypto';
     8→import { SignInDto } from '../dto/signin.dto';
     9→import { AuthResponseDto } from '../dto/auth-response.dto';
    10→import { RefreshTokenDto } from '../dto/refresh-token.dto';
    11→import { JwtPayload } from '../strategies/jwt.strategy';
    12→
    13→@Injectable()
    14→export class AuthService {
    15→  constructor(
    16→    @Inject(DATABASE_CONNECTION_TOKEN)
    17→    private readonly db: Db,
    18→    private readonly jwtService: JwtService,
    19→    @Inject(jwtConfig.KEY)
    20→    private readonly config: ConfigType<typeof jwtConfig>,
    21→  ) {}
    22→
    23→  async signIn(signInDto: SignInDto): Promise<AuthResponseDto> {
    24→    const trx = await this.db.startTransaction().execute();
    25→
    26→    try {
    27→      const user = await trx
    28→        .selectFrom('user')
    29→        .selectAll()
    30→        .where('email', '=', signInDto.email)
    31→        .where('isActive', '=', true)
    32→        .executeTakeFirst();
    33→
    34→      if (!user) {
    35→        throw new UnauthorizedException('Invalid credentials');
    36→      }
    37→
    38→      const isPasswordValid = signInDto.password === user.password;
    39→
    40→      if (!isPasswordValid) {
    41→        throw new UnauthorizedException('Invalid credentials');
    42→      }
    43→
    44→      // Generate refresh token
    45→      const refreshTokenValue = randomBytes(64).toString('hex');
    46→      const expiresAt = new Date();
    47→      expiresAt.setTime(
    48→        expiresAt.getTime() +
    49→          this.parseExpiration(this.config.refreshTokenExpiresIn) * 1000,
    50→      );
    51→
    52→      // Store refresh token in database
    53→      const refreshToken = await trx
    54→        .insertInto('refreshToken')
    55→        .values({
    56→          token: refreshTokenValue,
    57→          userId: user.id,
    58→          expiresAt: expiresAt,
    59→        })
    60→        .returningAll()
    61→        .executeTakeFirstOrThrow();
    62→
    63→      // Generate access token
    64→      const accessTokenPayload: JwtPayload = {
    65→        sub: user.id as string,
    66→        email: user.email,
    67→        tenantId: user.tenantId,
    68→      };
    69→
    70→      const accessToken = this.jwtService.sign(accessTokenPayload, {
    71→        expiresIn: this.config.accessTokenExpiresIn,
    72→      } as JwtSignOptions);
    73→
    74→      // Generate refresh token JWT (contains the DB token ID for validation)
    75→      const refreshTokenPayload = {
    76→        sub: user.id,
    77→        tokenId: refreshToken.id as string,
    78→      };
    79→
    80→      const refreshTokenJwt = this.jwtService.sign(refreshTokenPayload, {
    81→        expiresIn: this.config.refreshTokenExpiresIn,
    82→      } as JwtSignOptions);
    83→
    84→      await trx.commit().execute();
    85→
    86→      return {
    87→        accessToken,
    88→        refreshToken: refreshTokenJwt,
    89→      };
    90→    } catch (error) {
    91→      await trx.rollback().execute();
    92→      throw error;
    93→    }
    94→  }
    95→
    96→  async refresh(refreshTokenDto: RefreshTokenDto): Promise<AuthResponseDto> {
    97→    const trx = await this.db.startTransaction().execute();
    98→    try {
    99→      // Verify and decode refresh token
   100→      const decoded = this.jwtService.verify(refreshTokenDto.refreshToken) as {
   101→        sub: string;
   102→        tokenId: string;
   103→      };
   104→
   105→      // Check if refresh token exists in database and is valid
   106→      const refreshToken = await trx
   107→        .selectFrom('refreshToken')
   108→        .innerJoin('user', 'refreshToken.userId', 'user.id')
   109→        .select([
   110→          'refreshToken.id',
   111→          'refreshToken.token',
   112→          'refreshToken.userId',
   113→          'refreshToken.expiresAt',
   114→          'user.email',
   115→          'user.tenantId',
   116→          'user.isActive',
   117→        ])
   118→        .where('refreshToken.id', '=', decoded.tokenId as UUID)
   119→        .where('refreshToken.expiresAt', '>', new Date())
   120→        .where('user.isActive', '=', true)
   121→        .executeTakeFirst();
   122→
   123→      if (!refreshToken) {
   124→        throw new UnauthorizedException('Invalid or expired refresh token');
   125→      }
   126→
   127→      // Delete old refresh token
   128→      await trx
   129→        .deleteFrom('refreshToken')
   130→        .where('id', '=', refreshToken.id)
   131→        .execute();
   132→
   133→      // Generate new tokens
   134→      const newRefreshTokenValue = randomBytes(64).toString('hex');
   135→      const expiresAt = new Date();
   136→      expiresAt.setTime(
   137→        expiresAt.getTime() +
   138→          this.parseExpiration(this.config.refreshTokenExpiresIn) * 1000,
   139→      );
   140→
   141→      const newRefreshToken = await trx
   142→        .insertInto('refreshToken')
   143→        .values({
   144→          token: newRefreshTokenValue,
   145→          userId: refreshToken.userId,
   146→          expiresAt: expiresAt,
   147→        })
   148→        .returningAll()
   149→        .executeTakeFirstOrThrow();
   150→
   151→      // Generate new access token
   152→      const accessTokenPayload: JwtPayload = {
   153→        sub: refreshToken.userId as string,
   154→        email: refreshToken.email,
   155→        tenantId: refreshToken.tenantId,
   156→      };
   157→
   158→      const accessToken = this.jwtService.sign(accessTokenPayload, {
   159→        expiresIn: this.config.accessTokenExpiresIn,
   160→      } as JwtSignOptions);
   161→
   162→      // Generate new refresh token JWT
   163→      const refreshTokenPayload = {
   164→        sub: refreshToken.userId as string,
   165→        tokenId: newRefreshToken.id as string,
   166→      };
   167→
   168→      const refreshTokenJwt = this.jwtService.sign(refreshTokenPayload, {
   169→        expiresIn: this.config.refreshTokenExpiresIn,
   170→      } as JwtSignOptions);
   171→
   172→      await trx.commit().execute();
   173→
   174→      return {
   175→        accessToken,
   176→        refreshToken: refreshTokenJwt,
   177→      };
   178→    } catch (error) {
   179→      await trx.rollback().execute();
   180→      if (error instanceof UnauthorizedException) {
   181→        throw error;
   182→      }
   183→      throw new UnauthorizedException('Invalid refresh token');
   184→    }
   185→  }
   186→
   187→  async logout(userId: UUID): Promise<{ message: string }> {
   188→    // Delete all refresh tokens for this user
   189→    await this.db
   190→      .deleteFrom('refreshToken')
   191→      .where('userId', '=', userId)
   192→      .execute();
   193→
   194→    return {
   195→      message: 'Logged out successfully',
   196→    };
   197→  }
   198→
   199→  private parseExpiration(expiresIn: string): number {
   200→    // Parse expiration string like "7d", "15m", "1h" to seconds
   201→    const match = expiresIn.match(/^(\d+)([smhd])$/);
   202→    if (!match) {
   203→      return 7 * 24 * 60 * 60; // Default to 7 days in seconds
   204→    }
   205→
   206→    const value = parseInt(match[1], 10);
   207→    const unit = match[2];
   208→
   209→    switch (unit) {
   210→      case 's':
   211→        return value;
   212→      case 'm':
   213→        return value * 60;
   214→      case 'h':
   215→        return value * 60 * 60;
   216→      case 'd':
   217→        return value * 24 * 60 * 60;
   218→      default:
   219→        return 7 * 24 * 60 * 60;
   220→    }
   221→  }
   222→}
