     1→import 'reflect-metadata';
     2→import { HttpException, HttpStatus, Inject } from '@nestjs/common';
     3→import {
     4→  RateLimiterRedis,
     5→  IRateLimiterRedisOptions,
     6→  RateLimiterRes,
     7→} from 'rate-limiter-flexible';
     8→import { IRedisClient } from '@podkopaev-tech/nest-infra-modules';
     9→
    10→export interface RateLimiterDecoratorOptions extends Omit<
    11→  IRateLimiterRedisOptions,
    12→  'storeClient' | 'points' | 'duration' | 'useRedisPackage'
    13→> {
    14→  /**
    15→   * Token to inject the Redis client.
    16→   */
    17→  redisToken: string | symbol;
    18→
    19→  /**
    20→   * aka count of available requests
    21→   */
    22→  points: number;
    23→
    24→  /**
    25→   * duration window in milliseconds
    26→   */
    27→  durationWindowMs: number;
    28→
    29→  /**
    30→   * Optional function to generate a custom key for rate limiting.
    31→   * By default, uses: `${constructor.name}:${methodName}`
    32→   */
    33→  keyResolver?: (
    34→    target: unknown,
    35→    propertyKey: string | symbol,
    36→    args: unknown[],
    37→  ) => string;
    38→
    39→  /**
    40→   * Optional function to customize the error thrown when rate limited.
    41→   * Receives the rate limiter response with retryAfter and remaining points.
    42→   */
    43→  onLimitReached?: (res: RateLimiterRes) => unknown;
    44→}
    45→
    46→/**
    47→ * Decorator that rate limits method calls using Redis.
    48→ *
    49→ * @example
    50→ * ```typescript
    51→ * @RateLimiter({
    52→ *   points: 10, // Number of requests
    53→ *   duration: 60, // Per 60 seconds
    54→ *   redisToken: 'REDIS_CLIENT', // Token for Redis client injection
    55→ * })
    56→ * async myMethod() {
    57→ *   // This method will be rate limited to 10 calls per 60 seconds
    58→ * }
    59→ * ```
    60→ */
    61→export const RateLimiter = (
    62→  options: RateLimiterDecoratorOptions,
    63→): MethodDecorator => {
    64→  return (
    65→    target: object,
    66→    propertyKey: string | symbol,
    67→    descriptor: PropertyDescriptor,
    68→  ) => {
    69→    if (!descriptor.value) {
    70→      throw new Error('@RateLimiter can only be applied to methods.');
    71→    }
    72→
    73→    const originalMethod = descriptor.value;
    74→    const redisToken = options.redisToken;
    75→
    76→    // Set up property injection for Redis client if not already present
    77→    if (!(redisToken in target)) {
    78→      Inject(redisToken)(target, redisToken);
    79→    }
    80→
    81→    // Remove redisToken from options before passing to RateLimiterRedis
    82→    const {
    83→      redisToken: _redisToken,
    84→      keyResolver,
    85→      onLimitReached,
    86→      ...rateLimiterOptions
    87→    } = options;
    88→
    89→    // Use a symbol to store the rate limiter instance on each instance
    90→    const rateLimiterKey = Symbol(`rateLimiter_${String(propertyKey)}`);
    91→
    92→    descriptor.value = async function (this: unknown, ...args: unknown[]) {
    93→      // Access Redis client from the instance (injected by NestJS at runtime)
    94→      const redisClient: IRedisClient = this[redisToken];
    95→
    96→      if (!redisClient) {
    97→        throw new Error(
    98→          `Redis client not injected. Make sure to provide the redisToken or inject Redis client with token: ${String(redisToken)}`,
    99→        );
   100→      }
   101→
   102→      // Lazy initialization: create rate limiter on first call and cache it
   103→      if (!this[rateLimiterKey]) {
   104→        this[rateLimiterKey] = new RateLimiterRedis({
   105→          points: options.points,
   106→          duration: options.durationWindowMs / 1000,
   107→          ...rateLimiterOptions,
   108→          storeClient: redisClient,
   109→        });
   110→      }
   111→
   112→      const rateLimiter = this[rateLimiterKey] as RateLimiterRedis;
   113→
   114→      // Generate the key for rate limiting
   115→      let key: string;
   116→      if (keyResolver) {
   117→        key = keyResolver(this, propertyKey, args);
   118→      } else {
   119→        key = `${this.constructor.name}:${String(propertyKey)}`;
   120→      }
   121→
   122→      try {
   123→        // Attempt to consume a point (this will throw if rate limit is exceeded)
   124→        await rateLimiter.consume(key);
   125→
   126→        // If we get here, rate limit check passed, proceed with original method
   127→        return originalMethod.apply(this, args);
   128→      } catch (rejRes: unknown) {
   129→        // Rate limit exceeded
   130→        if (rejRes instanceof Error) {
   131→          throw rejRes;
   132→        }
   133→
   134→        // rejRes is RateLimiterRes with msBeforeNext, remainingPoints, totalHitsPerKey
   135→        const rateLimiterRes = rejRes as RateLimiterRes;
   136→
   137→        if (onLimitReached) {
   138→          throw onLimitReached(rateLimiterRes);
   139→        }
   140→
   141→        // Default error
   142→        throw new HttpException(
   143→          `Rate limit exceeded. Try again in ${Math.round(rateLimiterRes.msBeforeNext / 1000)} seconds.`,
   144→          HttpStatus.TOO_MANY_REQUESTS,
   145→        );
   146→      }
   147→    };
   148→  };
   149→};
